/*! MiniChart v1.0 — Chart.js-compatible canvas renderer for ميزانيتي */
(function(global){
'use strict';

// ── Chart defaults (compatible with Chart.js API) ──
const defaults = {
  font: { family: 'Cairo, sans-serif', size: 12 },
  color: '#8492a6',
  responsive: true
};

const _instances = new WeakMap();

function hexToRgba(hex, alpha) {
  if (!hex || typeof hex !== 'string') return `rgba(100,100,100,${alpha})`;
  // handle hsla/rgba directly
  if (hex.startsWith('hsla') || hex.startsWith('rgba') || hex.startsWith('rgb')) return hex;
  if (hex.startsWith('hsl')) {
    const m = hex.match(/hsl\((\d+),\s*([\d.]+)%,\s*([\d.]+)%\)/);
    if (m) {
      const [h,s,l] = [+m[1], +m[2]/100, +m[3]/100];
      const a2 = s * Math.min(l, 1-l);
      const f = n => { const k=(n+h/30)%12; return l - a2*Math.max(Math.min(k-3,9-k,1),-1); };
      return `rgba(${Math.round(f(0)*255)},${Math.round(f(8)*255)},${Math.round(f(4)*255)},${alpha})`;
    }
    return `rgba(100,100,100,${alpha})`;
  }
  const c = hex.replace('#','');
  const full = c.length===3 ? c.split('').map(x=>x+x).join('') : c;
  const r=parseInt(full.substring(0,2),16)||0;
  const g=parseInt(full.substring(2,4),16)||0;
  const b=parseInt(full.substring(4,6),16)||0;
  return `rgba(${r},${g},${b},${alpha})`;
}

function parseColor(col, alpha) {
  if (!col) return `rgba(100,100,100,${alpha})`;
  if (col.startsWith('hsla')) {
    // inject alpha
    return col.replace(/[\d.]+\)$/, alpha+')');
  }
  return hexToRgba(col, alpha);
}

function dpr() { return window.devicePixelRatio || 1; }

function setHiDPI(canvas) {
  const rect = canvas.getBoundingClientRect();
  const w = rect.width  || canvas.offsetParent?.offsetWidth || 300;
  const h = rect.height || canvas.offsetParent?.offsetHeight || 200;
  const ratio = dpr();
  canvas.width  = Math.round(w * ratio);
  canvas.height = Math.round(h * ratio);
  canvas.style.width  = w + 'px';
  canvas.style.height = h + 'px';
  const ctx = canvas.getContext('2d');
  ctx.scale(ratio, ratio);
  return { w, h, ctx };
}

// ── Tooltip singleton ──
let tooltip = null;
function getTooltip() {
  if (!tooltip) {
    tooltip = document.createElement('div');
    tooltip.style.cssText = 'position:fixed;pointer-events:none;background:rgba(15,20,30,0.92);color:#f1f5f9;padding:7px 11px;border-radius:7px;font-size:12px;font-family:Cairo,sans-serif;box-shadow:0 4px 14px rgba(0,0,0,.5);z-index:9999;opacity:0;transition:opacity .15s';
    document.body.appendChild(tooltip);
  }
  return tooltip;
}
function showTooltip(x, y, html) {
  const t = getTooltip();
  t.innerHTML = html;
  t.style.opacity = '1';
  t.style.left = (x + 12) + 'px';
  t.style.top  = (y - 10) + 'px';
}
function hideTooltip() {
  const t = getTooltip();
  if (t) t.style.opacity = '0';
}

// ────────────────────────────────────────────
// Chart Class
// ────────────────────────────────────────────
class Chart {
  constructor(canvas, config) {
    if (!canvas) return;
    this.canvas  = canvas;
    this.config  = config;
    this.type    = config.type;
    this.data    = config.data;
    this.options = config.options || {};
    this._resizeHandler = null;
    this._render();
    this._attachEvents();
    if (this.options.responsive !== false) this._watchResize();
  }

  destroy() {
    if (this._ro) this._ro.disconnect();
    if (this._resizeHandler) window.removeEventListener('resize', this._resizeHandler);
    const ctx = this.canvas?.getContext('2d');
    if (ctx) ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
    hideTooltip();
    this._hitAreas = [];
  }

  update() { this._render(); }

  _render() {
    const c = this.canvas;
    if (!c) return;
    const { w, h, ctx } = setHiDPI(c);
    this._w = w; this._h = h; this._ctx = ctx;
    if (this.type === 'doughnut') this._drawDoughnut(ctx, w, h);
    else if (this.type === 'bar')  this._drawBar(ctx, w, h);
    else if (this.type === 'line') this._drawLine(ctx, w, h);
  }

  // ── DOUGHNUT ──────────────────────────────
  _drawDoughnut(ctx, w, h) {
    const opts    = this.options;
    const dataset = this.data.datasets[0];
    const labels  = this.data.labels || [];
    const values  = dataset.data.map(v => Math.max(0, parseFloat(v)||0));
    const colors  = dataset.backgroundColor || [];
    const total   = values.reduce((a,b)=>a+b, 0);
    const legendH = opts.plugins?.legend?.position === 'bottom' ? this._legendHeight(labels) : 0;
    const cutoutPct = parseFloat(opts.cutout) / 100 || 0.65;

    const chartH = h - legendH - 4;
    const cx = w / 2;
    const cy = chartH / 2;
    const outerR = Math.min(w, chartH) / 2 - 8;
    const innerR = outerR * cutoutPct;
    const borderColor = dataset.borderColor || '#000';
    const borderW     = dataset.borderWidth  || 2;

    this._hitAreas = [];

    if (total <= 0) {
      ctx.beginPath();
      ctx.arc(cx, cy, outerR, 0, Math.PI*2);
      ctx.arc(cx, cy, innerR, 0, Math.PI*2, true);
      ctx.fillStyle = 'rgba(255,255,255,0.05)';
      ctx.fill();
      return;
    }

    let startAngle = -Math.PI / 2;
    values.forEach((val, i) => {
      if (val === 0) return;
      const slice = (val / total) * Math.PI * 2;
      const endAngle = startAngle + slice;
      const color = typeof colors === 'string' ? colors : (colors[i] || '#888');

      ctx.beginPath();
      ctx.moveTo(cx, cy);
      ctx.arc(cx, cy, outerR, startAngle, endAngle);
      ctx.arc(cx, cy, innerR, endAngle, startAngle, true);
      ctx.closePath();
      ctx.fillStyle = color;
      ctx.fill();
      ctx.strokeStyle = borderColor;
      ctx.lineWidth   = borderW;
      ctx.stroke();

      this._hitAreas.push({ type:'arc', cx, cy, innerR, outerR, startAngle, endAngle, label: labels[i]||'', value: val, color });
      startAngle = endAngle;
    });

    // Legend
    if (opts.plugins?.legend?.position === 'bottom') {
      const lOpts  = opts.plugins.legend.labels || {};
      const fSize  = lOpts.font?.size || 11;
      const fam    = lOpts.font?.family || defaults.font.family;
      const pad    = lOpts.padding || 12;
      const color  = lOpts.color  || defaults.color;
      ctx.font = `${fSize}px ${fam}`;
      ctx.textAlign = 'start';
      ctx.textBaseline = 'middle';

      const items = labels.map((l,i) => ({ label: l, color: colors[i]||'#888' }));
      const dotW  = fSize * 0.75;
      let rx = 8, ry = h - legendH + 10;
      const rowH = fSize + pad;

      items.forEach((item) => {
        const tw = ctx.measureText(item.label).width;
        const itemW = dotW + 6 + tw + pad;
        if (rx + itemW > w - 8) { rx = 8; ry += rowH; }
        ctx.beginPath();
        ctx.arc(rx + dotW/2, ry, dotW/2, 0, Math.PI*2);
        ctx.fillStyle = item.color;
        ctx.fill();
        ctx.fillStyle = color;
        ctx.fillText(item.label, rx + dotW + 6, ry);
        rx += itemW;
      });
    }
  }

  _legendHeight(labels) {
    const lOpts = this.options.plugins?.legend?.labels || {};
    const fSize = lOpts.font?.size || 11;
    const pad   = lOpts.padding || 12;
    const cols  = Math.max(1, Math.floor((this._w||300) / 90));
    const rows  = Math.ceil(labels.length / cols);
    return rows * (fSize + pad) + 8;
  }

  // ── BAR ──────────────────────────────────
  _drawBar(ctx, w, h) {
    const opts    = this.options;
    const dataset = this.data.datasets[0];
    const labels  = this.data.labels || [];
    const values  = dataset.data.map(v => parseFloat(v)||0);
    const color   = dataset.backgroundColor || 'rgba(79,124,255,0.5)';
    const borderC = dataset.borderColor || '#4f7cff';
    const borderR = dataset.borderRadius || 3;

    const scOpts = opts.scales || {};
    const xTick  = scOpts.x?.ticks || {};
    const yTick  = scOpts.y?.ticks || {};
    const gridCX  = scOpts.x?.grid?.color || 'rgba(255,255,255,0.04)';
    const gridCY  = scOpts.y?.grid?.color || 'rgba(255,255,255,0.04)';
    const tickCol = xTick.color || '#4a5568';
    const yTickCol= yTick.color || '#4a5568';
    const fSize  = 9;
    const fam    = defaults.font.family;

    const PAD_L = 40, PAD_R = 8, PAD_T = 12, PAD_B = 28;
    const chartW = w - PAD_L - PAD_R;
    const chartH = h - PAD_T - PAD_B;

    const maxVal = Math.max(...values, 1);
    const minVal = Math.min(...values, 0);
    const yRange = maxVal - minVal || 1;

    // Y grid
    const ySteps = 4;
    ctx.font = `${fSize}px ${fam}`;
    for (let i=0; i<=ySteps; i++) {
      const yVal = minVal + (yRange * i / ySteps);
      const yPx  = PAD_T + chartH - (chartH * i / ySteps);
      ctx.beginPath();
      ctx.strokeStyle = gridCY;
      ctx.lineWidth   = 1;
      ctx.moveTo(PAD_L, yPx);
      ctx.lineTo(PAD_L + chartW, yPx);
      ctx.stroke();
      const label = yTick.callback ? yTick.callback(yVal) : (yVal >= 1000 ? (yVal/1000).toFixed(0)+'ك' : yVal.toFixed(0));
      ctx.fillStyle = yTickCol;
      ctx.textAlign = 'end';
      ctx.textBaseline = 'middle';
      ctx.fillText(label, PAD_L - 4, yPx);
    }

    // bars
    const bw = Math.max(4, chartW / Math.max(values.length, 1) * 0.6);
    const gap = chartW / Math.max(values.length, 1);
    this._hitAreas = [];

    values.forEach((val, i) => {
      const bh   = val <= 0 ? 0 : Math.max(2, (val / yRange) * chartH);
      const bx   = PAD_L + i * gap + (gap - bw) / 2;
      const by   = PAD_T + chartH - bh;

      const r = Math.min(borderR, bh/2, bw/2);
      ctx.beginPath();
      ctx.moveTo(bx + r, by);
      ctx.lineTo(bx + bw - r, by);
      ctx.quadraticCurveTo(bx + bw, by, bx + bw, by + r);
      ctx.lineTo(bx + bw, by + bh);
      ctx.lineTo(bx, by + bh);
      ctx.lineTo(bx, by + r);
      ctx.quadraticCurveTo(bx, by, bx + r, by);
      ctx.closePath();
      ctx.fillStyle = color;
      ctx.fill();
      ctx.strokeStyle = borderC;
      ctx.lineWidth = dataset.borderWidth || 1;
      ctx.stroke();

      this._hitAreas.push({ type:'bar', bx, by, bw, bh: Math.max(bh,1), label: labels[i]||'', value: val });

      // X label
      if (i % Math.ceil(values.length / 15) === 0) {
        ctx.fillStyle = tickCol;
        ctx.textAlign  = 'center';
        ctx.textBaseline = 'top';
        ctx.font = `${fSize}px ${fam}`;
        ctx.fillText(labels[i]||'', bx + bw/2, PAD_T + chartH + 4);
      }
    });
  }

  // ── LINE ──────────────────────────────────
  _drawLine(ctx, w, h) {
    const opts    = this.options;
    const dataset = this.data.datasets[0];
    const labels  = this.data.labels || [];
    const values  = dataset.data.map(v => parseFloat(v)||0);
    const lineCol = dataset.borderColor || '#4f7cff';
    const fillCol = dataset.backgroundColor || parseColor(lineCol, 0.06);

    const scOpts = opts.scales || {};
    const xTick  = scOpts.x?.ticks || {};
    const yTick  = scOpts.y?.ticks || {};
    const gridCY  = scOpts.y?.grid?.color || 'rgba(255,255,255,0.04)';
    const tickCol = xTick.color || '#4a5568';
    const yTickCol= yTick.color || '#4a5568';
    const fSize  = 10;
    const fam    = defaults.font.family;
    const tension = dataset.tension || 0.4;

    const PAD_L = 44, PAD_R = 8, PAD_T = 12, PAD_B = 28;
    const chartW = w - PAD_L - PAD_R;
    const chartH = h - PAD_T - PAD_B;

    if (values.length < 2) return;
    const maxVal = Math.max(...values);
    const minVal = Math.min(...values);
    const yRange = maxVal - minVal || 1;
    const yPad   = yRange * 0.1;

    const xStep = chartW / (values.length - 1);

    const toX = i => PAD_L + i * xStep;
    const toY = v => PAD_T + chartH - ((v - minVal + yPad) / (yRange + yPad*2)) * chartH;

    // Y grid lines
    const ySteps = 4;
    ctx.font = `${fSize}px ${fam}`;
    for (let i=0; i<=ySteps; i++) {
      const yVal = minVal + (yRange * i / ySteps);
      const yPx  = toY(yVal);
      ctx.beginPath();
      ctx.strokeStyle = gridCY;
      ctx.lineWidth   = 1;
      ctx.moveTo(PAD_L, yPx);
      ctx.lineTo(PAD_L + chartW, yPx);
      ctx.stroke();
      const label = yTick.callback ? yTick.callback(yVal) : (Math.abs(yVal)>=1000 ? (yVal/1000).toFixed(1)+'ك' : yVal.toFixed(0));
      ctx.fillStyle = yTickCol;
      ctx.textAlign = 'end';
      ctx.textBaseline = 'middle';
      ctx.fillText(label, PAD_L - 4, yPx);
    }

    // Fill area
    if (dataset.fill) {
      ctx.beginPath();
      ctx.moveTo(toX(0), PAD_T + chartH);
      ctx.lineTo(toX(0), toY(values[0]));
      for (let i=1; i<values.length; i++) {
        const cp1x = toX(i-1) + xStep * tension;
        const cp1y = toY(values[i-1]);
        const cp2x = toX(i)   - xStep * tension;
        const cp2y = toY(values[i]);
        ctx.bezierCurveTo(cp1x, cp1y, cp2x, cp2y, toX(i), toY(values[i]));
      }
      ctx.lineTo(toX(values.length-1), PAD_T + chartH);
      ctx.closePath();
      ctx.fillStyle = fillCol;
      ctx.fill();
    }

    // Line
    ctx.beginPath();
    ctx.moveTo(toX(0), toY(values[0]));
    for (let i=1; i<values.length; i++) {
      const cp1x = toX(i-1) + xStep * tension;
      const cp1y = toY(values[i-1]);
      const cp2x = toX(i)   - xStep * tension;
      const cp2y = toY(values[i]);
      ctx.bezierCurveTo(cp1x, cp1y, cp2x, cp2y, toX(i), toY(values[i]));
    }
    ctx.strokeStyle = lineCol;
    ctx.lineWidth   = dataset.borderWidth || 2;
    ctx.lineJoin    = 'round';
    ctx.stroke();

    // X labels — sparse
    const step = Math.ceil(values.length / 8);
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    ctx.fillStyle = tickCol;
    ctx.font = `${fSize}px ${fam}`;
    for (let i=0; i<values.length; i+=step) {
      ctx.fillText(labels[i]||'', toX(i), PAD_T + chartH + 4);
    }

    // Store hit areas
    this._hitAreas = values.map((v,i) => ({ type:'point', x: toX(i), y: toY(v), r: 16, label: labels[i]||'', value: v }));
  }

  // ── EVENTS ────────────────────────────────
  _attachEvents() {
    if (!this.canvas) return;
    const onMove = (e) => {
      const rect = this.canvas.getBoundingClientRect();
      const clientX = e.touches ? e.touches[0].clientX : e.clientX;
      const clientY = e.touches ? e.touches[0].clientY : e.clientY;
      const mx = clientX - rect.left;
      const my = clientY - rect.top;
      const hit = this._findHit(mx, my);
      if (hit) {
        const cbLabel = this.options.plugins?.tooltip?.callbacks?.label;
        const parsed = this.type === 'bar' ? { y: hit.value } : hit.value;
        const labelStr = cbLabel ? cbLabel({ parsed, label: hit.label }) : hit.value;
        showTooltip(clientX, clientY, `<span style="color:${hit.color||'#f1f5f9'}">${hit.label}</span><br>${labelStr}`);
      } else hideTooltip();
    };
    const onLeave = () => hideTooltip();
    this.canvas.addEventListener('mousemove', onMove, { passive:true });
    this.canvas.addEventListener('mouseleave', onLeave);
    this.canvas.addEventListener('touchmove', onMove, { passive:true });
    this.canvas.addEventListener('touchend', onLeave);
    this._cleanupEvents = () => {
      this.canvas.removeEventListener('mousemove', onMove);
      this.canvas.removeEventListener('mouseleave', onLeave);
    };
  }

  _findHit(mx, my) {
    if (!this._hitAreas) return null;
    for (const h of this._hitAreas) {
      if (h.type === 'arc') {
        const dx = mx - h.cx, dy = my - h.cy;
        const dist = Math.sqrt(dx*dx + dy*dy);
        if (dist >= h.innerR && dist <= h.outerR) {
          const angle = Math.atan2(dy, dx);
          const a = angle < -Math.PI/2 ? angle + Math.PI*2 : angle;
          const sa = h.startAngle < -Math.PI/2 ? h.startAngle + Math.PI*2 : h.startAngle;
          const ea = h.endAngle   < -Math.PI/2 ? h.endAngle   + Math.PI*2 : h.endAngle;
          if (a >= sa && a <= ea) return h;
        }
      } else if (h.type === 'bar') {
        if (mx >= h.bx && mx <= h.bx + h.bw && my >= h.by && my <= h.by + h.bh) return h;
      } else if (h.type === 'point') {
        if (Math.abs(mx - h.x) < h.r) return h;
      }
    }
    return null;
  }

  _watchResize() {
    if (typeof ResizeObserver !== 'undefined') {
      this._ro = new ResizeObserver(() => this._render());
      this._ro.observe(this.canvas.parentElement || this.canvas);
    }
  }
}

// ── Chart.defaults ──
Chart.defaults = defaults;

// ── Expose globally ──
global.Chart = Chart;

})(typeof window !== 'undefined' ? window : this);
